175→impl Component for Repl {
176→    type Message = Msg;
177→    type Properties = ();
178→
179→    fn create(ctx: &Context<Self>) -> Self {
180→        ctx.link().send_message(Msg::Init);
181→
182→        Self {
183→            emulator: {
184→                let mut emu = EmulatorCore::new();
185→                emu.set_uart_tx_busy_cycles(0); // instant TX in browser
186→                emu
187→            },
188→            output: String::new(),
189→            transcript: String::new(),
190→            uart_seen: 0,
191→            input: String::from("(+ 1 2)"),
192→            status: "Assembling interpreter...".into(),
193→            running: false,
194→            loaded: false,
195→            waiting_for_input: false,
196→            uart_tx_queue: VecDeque::new(),
197→            prelude: PreludeTier::Standard,
198→            stack_size: StackSize::ThreeKb,
199→            led_on: false,
200→            switch_pressed: false,
201→            view_mode: ViewMode::Cli,
202→            selected_demo: None,
203→            addr_heap_next: None,
204→            addr_sym_count: None,
205→            addr_str_pool_next: None,
206→            heap_used: 0,
207→            sym_used: 0,
208→            str_pool_used: 0,
209→            stack_depth: 0,
210→            cpu_load: 0.0,
211→            input_ref: NodeRef::default(),
212→            cli_input_ref: NodeRef::default(),
213→        }
214→    }
215→
216→    fn update(&mut self, ctx: &Context<Self>, msg: Self::Message) -> bool {
217→        match msg {
218→            Msg::Init => {
219→                self.load_binary();
220→                if self.loaded {
221→                    ctx.link().send_message(Msg::Tick);
222→                }
223→                true
224→            }
225→
226→            Msg::Tick => {
227→                if !self.running {
228→                    return false;
229→                }
230→
231→                // Feed queued bytes: poll-before-feed (match cor24-run).
232→                // Budget limits total instructions to avoid blocking the
233→                // browser when the interpreter is busy evaluating.
234→                let mut feed_budget: u32 = 10_000;
235→                while !self.uart_tx_queue.is_empty() && feed_budget > 0 {
236→                    let status = self.emulator.read_byte(0xFF0101);
237→                    if status & 0x01 != 0 {
238→                        // CPU hasn't consumed previous byte — run a bit more
239→                        self.emulator.run_batch(50);
240→                        feed_budget = feed_budget.saturating_sub(50);
241→                        continue;
242→                    }
243→                    let byte = self.uart_tx_queue.pop_front().unwrap();
244→                    self.emulator.send_uart_byte(byte);
245→                    self.emulator.run_batch(50);
246→                    feed_budget = feed_budget.saturating_sub(50);
247→                    if byte == b'\n' {
248→                        break;
249→                    }
250→                }
251→
252→                let result = self.emulator.run_batch(BATCH_SIZE);
253→
254→                // EWMA of CPU utilization: how much of the batch budget was used
255→                let utilization = result.instructions_run as f64 / BATCH_SIZE as f64;
256→                const ALPHA: f64 = 0.15; // smoothing factor
257→                self.cpu_load = self.cpu_load * (1.0 - ALPHA) + utilization * ALPHA;
258→
259→                if result.led_changed {
260→                    self.led_on = self.emulator.get_led() & 1 != 0;
261→                }
262→
263→                // Sample memory usage from runtime globals
264→                if let Some(addr) = self.addr_heap_next {
265→                    self.heap_used = self.emulator.read_word(addr);
266→                }
267→                if let Some(addr) = self.addr_sym_count {
268→                    self.sym_used = self.emulator.read_word(addr);
269→                }
270→                if let Some(addr) = self.addr_str_pool_next {
271→                    self.str_pool_used = self.emulator.read_word(addr);
272→                }
273→                let sp = self.emulator.get_reg(4);
274→                self.stack_depth = self.stack_size.initial_sp().saturating_sub(sp);
275→
276→                let uart = self.emulator.get_uart_output();
277→                // Append new UART bytes to transcript (CLI view)
278→                if uart.len() > self.uart_seen {
279→                    self.transcript.push_str(&uart[self.uart_seen..]);
280→                    self.uart_seen = uart.len();
281→                }
282→                // Update raw output (Split view)
283→                let uart_owned = uart.to_string();
284→                if uart_owned != self.output {
285→                    self.output = uart_owned;
286→                }
287→
288→                match result.reason {
289→                    StopReason::CycleLimit => {
290→                        let at_prompt = self.uart_tx_queue.is_empty()
291→                            && self.output.ends_with("> ");
292→
293→                        if at_prompt {
294→                            self.running = false;
295→                            self.waiting_for_input = true;
296→                            self.cpu_load = 0.0;
297→                            self.status = "Ready.".into();
298→                        } else {
299→                            let link = ctx.link().clone();
300→                            Timeout::new(25, move || link.send_message(Msg::Tick)).forget();
301→                        }
302→                    }
303→                    StopReason::Halted => {
304→                        self.running = false;
305→                        self.waiting_for_input = false;
306→                        self.cpu_load = 0.0;
307→                        self.status = "Program finished.".into();
308→                    }
309→                    StopReason::InvalidInstruction(byte) => {
310→                        self.running = false;
311→                        self.status = format!(
312→                            "Invalid instruction 0x{:02X} at PC=0x{:06X}",
313→                            byte,
314→                            self.emulator.pc()
315→                        );
316→                    }
317→                    StopReason::Breakpoint(addr) => {
318→                        self.running = false;
319→                        self.status = format!("Breakpoint at 0x{:06X}", addr);
320→                    }
321→                    StopReason::Paused => {
322→                        self.running = false;
323→                        self.status = "Paused.".into();
324→                    }
325→                }
326→                true
327→            }
328→
329→            Msg::InputChanged(value) => {
330→                self.input = value;
331→                false
332→            }
333→
334→            Msg::Eval => {
335→                if !self.loaded {
336→                    return true;
337→                }
338→                // Echo input to transcript (CLI view shows interleaved I/O)
339→                for line in self.input.lines() {
340→                    if !line.trim().is_empty() {
341→                        self.transcript.push_str(line);
342→                        self.transcript.push('\n');
343→                    }
344→                }
345→                self.send_input();
346→                self.status = "Evaluating...".into();
347→                self.waiting_for_input = false;
348→                if !self.running {
349→                    self.emulator.resume();
350→                    self.running = true;
351→                    ctx.link().send_message(Msg::Tick);
352→                }
353→                // In CLI mode, clear the input after sending
354→                if self.view_mode == ViewMode::Cli {
355→                    self.input.clear();
356→                }
357→                true
358→            }
359→
360→            Msg::CliKeyDown(e) => {
361→                if e.key() == "Enter" && !e.shift_key() {
362→                    e.prevent_default();
363→                    ctx.link().send_message(Msg::Eval);
364→                }
365→                false
366→            }
367→
368→            Msg::SetPrelude(tier) => {
369→                if tier != self.prelude {
370→                    self.prelude = tier;
371→                    self.running = false;
372→                    self.load_binary();
373→                    if self.loaded {
374→                        ctx.link().send_message(Msg::Tick);
375→                    }
376→                }
377→                true
378→            }
379→
380→            Msg::SetStack(size) => {
381→                if size != self.stack_size {
382→                    self.stack_size = size;
383→                    self.running = false;
384→                    self.load_binary();
385→                    if self.loaded {
386→                        ctx.link().send_message(Msg::Tick);
387→                    }
388→                }
389→                true
390→            }
391→
392→            Msg::Reset => {
393→                self.running = false;
394→                self.load_binary();
395→                if self.loaded {
396→                    ctx.link().send_message(Msg::Tick);
397→                }
398→                true
399→            }
